#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int *mask = (int *)calloc(n, sizeof(int));
        for (int i = 0; i < m; ++i) {
            int v; scanf("%d", &v);
            for (int j = 0; j < v; ++j) {
                int x; scanf("%d", &x);
                mask[x] |= (1 << i);
            }
        }
        // count distinct masks
        int distinct = 0;
        for (int i = 0; i < n; ++i) {
            int seen = 0;
            for (int j = 0; j < i; ++j) {
                if (mask[j] == mask[i]) { seen = 1; break; }
            }
            if (!seen) ++distinct;
        }
        printf("%d\n", distinct);
        free(mask);
    }
    return 0;
}

