import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out = []
    for _ in range(T):
        n = next(it); m = next(it)
        mask = [0] * n
        for i in range(m):
            v = next(it)
            for _ in range(v):
                x = next(it)
                mask[x] |= (1 << i)
        out.append(str(len(set(mask))))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

